return items.map(item => {
  const meta = (item.json.metadata || item.json.body?.metadata || {});
  const idNegocio = String(meta.id_negocio || '').trim();
  const cedula = String(meta.cedula || '').trim();
  const modalidad = String(meta.modalidad || 'MODALIDAD EN LINEA').trim();
  const producto = String(meta.producto || '').trim();
  const nombreCampania = String(meta.nombre_corto_campania || '').trim();
  const phone = String((item.json.customer || item.json.body?.customer || {}).number || '0999999999');

  const hash = idNegocio.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0);
  const bucket = hash % 100;

  const nomNombre = [
    { nom: 'ACE', sentimiento: 'POSITIVO', resumen: 'Cliente acepto el plan de pagos y realizara la matricula en los proximos dias.' },
    { nom: 'IND', sentimiento: 'NEUTRAL', resumen: 'Cliente indeciso, necesita consultar con su familia antes de tomar una decision.' },
    { nom: 'NUE', sentimiento: 'POSITIVO', resumen: 'Cliente nuevo interesado en la carrera.' },
    { nom: 'VLL', sentimiento: 'NEUTRAL', resumen: 'Cliente solicito volver a llamar en otro horario.' },
    { nom: 'NC', sentimiento: null, resumen: 'Llamada dirigida al buzon de voz.' },
    { nom: 'NIN', sentimiento: 'NEGATIVO', resumen: '' }
  ];

  let ix;
  if (bucket < 15) ix = 0;
  else if (bucket < 25) ix = 1;
  else if (bucket < 35) ix = 2;
  else if (bucket < 55) ix = 3;
  else if (bucket < 75) ix = 4;
  else ix = 5;

  const selected = nomNombre[ix];
  let nom = selected.nom;
  let sentimiento = selected.sentimiento;
  let resumen = selected.resumen;
  let motivoVapi = selected.nom;

  if (nom === 'NIN') {
    const ninSub = [
      { motivo: 'Equivocado', keys: 'equivocado wrong error numero', sent: 'NEGATIVO' },
      { motivo: 'IVR De Empresa', keys: 'fax empresa oficina centralita', sent: 'NEUTRAL' },
      { motivo: 'Continuara por si solo', keys: 'cuenta propia por su cuenta solo', sent: 'NEUTRAL' },
      { motivo: 'Titular Esta Fuera Del Pais', keys: 'fuera del pais extranjero viaje', sent: 'NEGATIVO' },
      { motivo: 'Tercero o Familiar Pide No Llamar', keys: 'no llame no moleste no llamar', sent: 'NEGATIVO' },
      { motivo: 'Neg-Costos-No Tiene Dinero', keys: 'dinero costo caro pagar', sent: 'NEGATIVO' },
      { motivo: 'Neg-Pers-Problemas De Salud', keys: 'salud enfermo enfermedad medico', sent: 'NEGATIVO' },
      { motivo: 'Informacion Para Un Familiar', keys: 'para un familiar para mi hijo', sent: 'NEUTRAL' },
      { motivo: 'Neg-Pers-Aun No Es Bachiller', keys: 'bachiller colegio terminando', sent: 'NEUTRAL' },
      { motivo: 'Negativa-Pers-Titular Fallecido', keys: 'fallecio fallecido murio', sent: 'NEGATIVO' },
      { motivo: 'Estudiante Utpl 2Do. En Adelante', keys: 'estudiante continuo ya estudio', sent: 'NEUTRAL' },
      { motivo: 'Interesado En Maestria', keys: 'maestria posgrado postgrado', sent: 'NEUTRAL' },
      { motivo: 'No Ha Solicitado Informacion', keys: 'no solicite no pedi informacion', sent: 'NEGATIVO' },
      { motivo: 'Mala Experiencia Con Utpl', keys: 'mala experiencia mal servicio queja', sent: 'NEGATIVO' },
      { motivo: 'No Tiene Tiempo Para Estudiar', keys: 'no tengo tiempo ocupado', sent: 'NEGATIVO' },
      { motivo: 'No Esta Interesado En Modalidad En Linea', keys: 'presencial no en linea no modalidad en linea', sent: 'NEGATIVO' },
      { motivo: 'Estudia Ahora En Otra Univ', keys: 'otra universidad ya estudio en', sent: 'NEGATIVO' },
      { motivo: 'Carreras Ofertadas No Desea', keys: 'no ofertan no tiene la carrera', sent: 'NEGATIVO' },
      { motivo: 'Interesado Cursos Form. Perm', keys: 'cursos taller formacion permanente', sent: 'NEUTRAL' },
      { motivo: 'Interesado Proximo periodo', keys: 'proximo periodo siguiente ciclo', sent: 'NEUTRAL' },
      { motivo: 'No Localizable', keys: 'no localizable no contesta', sent: 'NEGATIVO' },
      { motivo: 'No Desea Continuar Con Proceso Matricula', keys: 'no desea no quiere no continua', sent: 'NEGATIVO' }
    ];
    const subIx = hash % ninSub.length;
    const sub = ninSub[subIx];
    motivoVapi = sub.motivo;
    resumen = 'Cliente indica que ' + sub.keys.split(' ').slice(0, 3).join(' ') + '. No muestra interes en continuar con el proceso de matricula en UTPL.';
    sentimiento = sub.sent;
  }

  const now = new Date();
  const endedAt = now.toISOString();
  const startedAt = new Date(now.getTime() - 45000).toISOString();
  const callId = 'sim-' + idNegocio + '-' + Date.now();
  const fechaGestion = endedAt.slice(0, 10);
  const horaGestion = now.toLocaleTimeString('en-GB', { timeZone: 'America/Guayaquil', hour12: false }).slice(0, 8);

  item.json.endOfCallReport = {
    message: {
      type: 'end-of-call-report',
      id: callId,
      endedAt: endedAt,
      startedAt: startedAt,
      endedReason: 'customer-ended-call',
      durationMs: 45000,
      durationSeconds: 45,
      transcript: resumen,
      summary: resumen,
      recordingUrl: null,
      customer: { number: phone },
      metadata: {
        id_negocio: idNegocio,
        cedula: cedula,
        modalidad: modalidad,
        producto: producto,
        nombre_corto_campania: nombreCampania
      },
      structuredOutputs: {
        '11111111-1111-1111-1111-111111111111': {
          name: 'Estado_Gestion_UTPL',
          result: { id_nomenclatura: nom, id_motivo: motivoVapi }
        },
        '22222222-2222-2222-2222-222222222222': {
          name: 'Sentimiento_Cliente',
          result: sentimiento || 'NEUTRAL'
        },
        '33333333-3333-3333-3333-333333333333': {
          name: 'Es Familiar',
          result: 'NO'
        },
        '44444444-4444-4444-4444-444444444444': {
          name: 'contactoalo',
          result: nom === 'NC' ? 'NO' : 'SI'
        },
        '55555555-5555-5555-5555-555555555555': {
          name: 'contactoefectivo',
          result: nom === 'NC' ? 'NO' : 'SI'
        },
        '66666666-6666-6666-6666-666666666666': {
          name: 'Resumen_Llamada',
          result: resumen
        },
        '77777777-7777-7777-7777-777777777777': {
          name: 'Cliente_Transferido',
          result: 'NO'
        }
      },
      id_negocio: idNegocio,
      cedula: cedula,
      fecha_gestion: fechaGestion,
      hora_gestion: horaGestion,
      id_llamada: callId,
      nomenclatura: nom,
      motivo: motivoVapi,
      es_familiar: 'NO',
      contactoalo: nom === 'NC' ? 'NO' : 'SI',
      contactoefectivo: nom === 'NC' ? 'NO' : 'SI',
      sentimiento: sentimiento,
      resumen_llamada: resumen,
      duracion_llamada: 45,
      customer_number: phone,
      numero_telefono: phone,
      status_sugerido: (nom === 'NC' || nom === 'VLL') ? 'REINTENTAR' : 'FINAL',
      estado_flujo: (nom === 'NC' || nom === 'VLL') ? 'REINTENTAR' : 'FINALIZADO'
    }
  };

  return item;
});
